<summary>Regression test</summary>

```c
#include <check.h>
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <unistd.h>
#include <sys/wait.h>

START_TEST(test_xxd_buffer_overflow_on_large_input)
{
    /* Invariant: Buffer reads never exceed the declared length.
     * xxd must not crash or corrupt memory when processing lines
     * that exceed internal buffer sizes. */
    const char *payloads[] = {
        /* Exact exploit: line exceeding typical 256-byte buffer */
        NULL,
        /* 10x oversize: 2560 bytes on a single line */
        NULL,
        /* Valid small input */
        "48656c6c6f0a"
    };

    /* Generate oversized hex payloads */
    char payload_256[513];
    memset(payload_256, '4', 512);
    payload_256[512] = '\0';
    payloads[0] = payload_256;

    char payload_2560[5121];
    memset(payload_2560, '4', 5120);
    payload_2560[5120] = '\0';
    payloads[1] = payload_2560;

    int num_payloads = sizeof(payloads) / sizeof(payloads[0]);

    for (int i = 0; i < num_payloads; i++) {
        char tmpfile[] = "/tmp/xxd_test_XXXXXX";
        int fd = mkstemp(tmpfile);
        ck_assert_int_ge(fd, 0);
        write(fd, payloads[i], strlen(payloads[i]));
        write(fd, "\n", 1);
        close(fd);

        /* Run xxd -r (revert mode) which exercises the strcpy(z, l) path */
        char cmd[512];
        snprintf(cmd, sizeof(cmd), "xxd -r %s > /dev/null 2>&1", tmpfile);
        int ret = system(cmd);
        /* Process must not be killed by signal (crash) */
        if (WIFSIGNALED(ret)) {
            int sig = WTERMSIG(ret);
            ck_assert_msg(sig == 0,
                "xxd crashed with signal %d on payload %d (len=%zu)",
                sig, i, strlen(payloads[i]));
        }
        unlink(tmpfile);
    }
}
END_TEST

Suite *security_suite(void)
{
    Suite *s;
    TCase *tc_core;

    s = suite_create("Security");
    tc_core = tcase_create("Core");

    tcase_add_test(tc_core, test_xxd_buffer_overflow_on_large_input);
    suite_add_tcase(s, tc_core);

    return s;
}

int main(void)
{
    int number_failed;
    Suite *s;
    SRunner *sr;

    s = security_suite();
    sr = srunner_create(s);

    srunner_run_all(sr, CK_NORMAL);
    number_failed = srunner_ntests_failed(sr);
    srunner_free(sr);

    return (number_failed == 0) ? EXIT_SUCCESS : EXIT_FAILURE;
}
```

</details>

